mapper.sql:
select temp.name as pe_name, temp.work_card as pe_work_card,temp.id_number as pe_id_number,temp.pe_id as pe_id, temp.contract_type, temp.start_time, temp.end_time, temp.contract_validity, temp.new_contract_flag, temp.remarks, temp.enabled_flag, temp.num as quantity, fdev.ext_dept_name AS pe_dept_name, fdev.ext_department_name AS pe_department, fdev.ext_team_name AS pe_team, fj.job_name as pe_pej_fj_job_name, pe_peen.entry_time as pe_peen_entryTime from (select pe.name, pe.work_card,pe.id_number,pe.leave_flag, pec.*, pe.id as pe_id, ROW_NUMBER() over( partition by pe.work_card order by pe.work_card, pec.start_time,pec.end_time) as num from pm_employee pe join pm_employee_contract pec on pe.id = pec.employee_id where pe.enabled_flag = 1 and pec.enabled_flag =1 ) temp left outer join pm_employee_job pej on temp.employee_id = pej.employee_id and pej.job_main_flag = 1 and pej.enabled_flag = 1 join fnd_job fj on fj.id = pej.job_id and fj.enabled_flag = 1 left outer join fnd_dept_ext_v fdev on pej.dept_id = fdev.id and fdev.enabled_flag = 1 and fdev.deleted_flag = 0 outer apply ( select top(1) pee.entry_time from pm_employee_entry pee where pee.employee_id = temp.employee_id AND pee.enabled_flag = 1 ) pe_peen where pej.enabled_flag = 1 and pej.job_main_flag = 1
and temp.new_contract_flag = #{criteria.newContractFlag, jdbcType = BIT}
and temp.pe_id = #{criteria.employeeId,jdbcType=BIGINT}
and temp.leave_flag = #{criteria.leaveFlag,jdbcType=BIT}
and temp.end_time >= #{criteria.beginDate,jdbcType=DATE} and temp.end_time <= #{criteria.endDate,jdbcType=DATE}
and temp.end_time >= #{criteria.selectTime,jdbcType=DATE}
and temp.end_time >= #{criteria.today,jdbcType=DATE} and temp.end_time <= #{criteria.selectTime,jdbcType=DATE}
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = temp.pe_id AND pej_t.enabled_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)

if.if:
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pec.employee_id AND pej_t.enabled_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)

mapper.update:

update pm_employee_contract
set enabled_flag      = #{enabledFlag,jdbcType=BIT},
    update_time       = #{updateTime,jdbcType=TIMESTAMP},
    update_by         = #{updateBy,jdbcType=BIGINT}
where id = #{id,jdbcType=BIGINT}


update pm_employee_contract
set new_contract_flag = #{newContractFlag,jdbcType=BIT},
    update_time       = #{updateTime,jdbcType=TIMESTAMP},
    update_by         = #{updateBy,jdbcType=BIGINT}
where employee_id = #{employee.id,jdbcType=BIGINT}
